+        typeof hooks?.applySlidesPayload === "function" &&
+        typeof hooks?.applyBgMessage === "function" &&
+        typeof hooks?.applySummaryMarkdown === "function" &&
+        typeof hooks?.getSlidesSummaryMarkdown === "function"
+      );
+    },
